// Pega a lista de mensagens do nó Redis
const messages = $input.first().json.messages;

let textoAgrupado = "";
let telefone = "";
const idsProcessados = new Set(); // evita colar msg duplicada em testes

const clinicaId = $('formatarDadosCredenciais').first().json.clinica_id;

// Se não tiver mensagens, devolve vazio de forma segura
if (!Array.isArray(messages) || messages.length === 0) {
  return [{
    json: {
      telefone: "",
      mensagem_final: "",
      clinica_id: clinicaId,
      chave_fila_redis: `fila:${clinicaId}:`
    }
  }];
}

// Percorre cada mensagem da fila
messages.forEach(msgString => {
  try {
    const msg = JSON.parse(msgString);
    telefone = msg.remoteJid;

    if (!idsProcessados.has(msg.id)) {
      idsProcessados.add(msg.id);
      textoAgrupado += msg.chatInput + "\n\n";
    }
  } catch (error) {
    // ignora erros de parse
  }
});

return [{
  json: {
    telefone: telefone,
    mensagem_final: textoAgrupado.trim(),
    clinica_id: clinicaId,
    chave_fila_redis: `fila:${clinicaId}:${telefone}`
  }
}];

